CREATE TABLE "ItemImage" ("id" TEXT NOT NULL,"itemId" TEXT NOT NULL,"imageUrl" TEXT NOT NULL,"publicId" TEXT,"sortOrder" INTEGER NOT NULL DEFAULT 0,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "ItemImage_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Category" ("id" TEXT NOT NULL,"name" TEXT NOT NULL,"slug" TEXT NOT NULL,"icon" TEXT,"isActive" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "Category_pkey" PRIMARY KEY ("id"));
CREATE TABLE "FinderIdentity" ("id" TEXT NOT NULL,"name" TEXT,"phone" TEXT,"whatsapp" TEXT,"email" TEXT,"phoneVerifiedAt" TIMESTAMP(3),"emailVerifiedAt" TIMESTAMP(3),"reputationScore" INTEGER NOT NULL DEFAULT 0,"successfulRecoveries" INTEGER NOT NULL DEFAULT 0,"helpfulReports" INTEGER NOT NULL DEFAULT 0,"falseReports" INTEGER NOT NULL DEFAULT 0,"avgResponseTime" INTEGER,"badges" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "FinderIdentity_pkey" PRIMARY KEY ("id"));
CREATE TABLE "FoundReport" ("id" TEXT NOT NULL,"recoveryCode" TEXT,"category" TEXT NOT NULL,"brand" TEXT,"modelNumber" TEXT,"color" TEXT,"identifyingMarks" TEXT,"description" TEXT NOT NULL,"foundLocation" TEXT NOT NULL,"foundDate" TIMESTAMP(3) NOT NULL,"photoUrl" TEXT,"finderName" TEXT,"finderPhone" TEXT,"finderWhatsapp" TEXT,"finderEmail" TEXT,"message" TEXT NOT NULL,"status" "FoundReportStatus" NOT NULL DEFAULT 'NEW',"finderIdentityId" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "FoundReport_pkey" PRIMARY KEY ("id"));
CREATE TABLE "FoundReportImage" ("id" TEXT NOT NULL,"foundReportId" TEXT NOT NULL,"imageUrl" TEXT NOT NULL,"publicId" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "FoundReportImage_pkey" PRIMARY KEY ("id"));
CREATE TABLE "FoundReportMatch" ("id" TEXT NOT NULL,"foundReportId" TEXT NOT NULL,"itemId" TEXT NOT NULL,"matchScore" INTEGER NOT NULL,"matchReason" TEXT NOT NULL,"status" "FoundMatchStatus" NOT NULL DEFAULT 'PENDING',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "FoundReportMatch_pkey" PRIMARY KEY ("id"));
CREATE TABLE "UserVerificationRequest" ("id" TEXT NOT NULL,"userId" TEXT NOT NULL,"type" "VerificationRequestType" NOT NULL,"status" "VerificationRequestStatus" NOT NULL DEFAULT 'PENDING',"documentUrl" TEXT,"reviewedByAdminId" TEXT,"rejectionReason" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "UserVerificationRequest_pkey" PRIMARY KEY ("id"));
CREATE TABLE "ItemVerification" ("id" TEXT NOT NULL,"itemId" TEXT NOT NULL,"type" "ItemVerificationType" NOT NULL,"documentUrl" TEXT,"serialNumberMasked" TEXT,"status" "ItemVerificationStatus" NOT NULL DEFAULT 'PENDING',"reviewedByAdminId" TEXT,"rejectionReason" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "ItemVerification_pkey" PRIMARY KEY ("id"));
CREATE TABLE "VerificationQuestion" ("id" TEXT NOT NULL,"conversationId" TEXT NOT NULL,"itemId" TEXT NOT NULL,"question" TEXT NOT NULL,"status" "VerificationQuestionStatus" NOT NULL DEFAULT 'DRAFT',"answer" TEXT,"askedByOwnerId" TEXT,"answeredAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "VerificationQuestion_pkey" PRIMARY KEY ("id"));
CREATE TABLE "RecoveryRequest" ("id" TEXT NOT NULL,"itemId" TEXT NOT NULL,"ownerId" TEXT NOT NULL,"foundReportId" TEXT,"conversationId" TEXT,"finderIdentityId" TEXT,"source" "RecoverySource" NOT NULL,"status" "RecoveryStatus" NOT NULL DEFAULT 'REGISTERED',"scheduledMeetingLocation" TEXT,"scheduledMeetingTime" TIMESTAMP(3),"ownerConfirmation" BOOLEAN,"finderConfirmation" BOOLEAN,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "RecoveryRequest_pkey" PRIMARY KEY ("id"));
CREATE TABLE "RecoveryTimelineEvent" ("id" TEXT NOT NULL,"recoveryRequestId" TEXT NOT NULL,"type" TEXT NOT NULL,"title" TEXT NOT NULL,"description" TEXT NOT NULL,"actorType" "RecoveryActorType" NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "RecoveryTimelineEvent_pkey" PRIMARY KEY ("id"));

