ALTER TABLE "RecoveryRequest" ADD CONSTRAINT "RecoveryRequest_itemId_fkey" FOREIGN KEY ("itemId") REFERENCES "Item"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "RecoveryRequest" ADD CONSTRAINT "RecoveryRequest_ownerId_fkey" FOREIGN KEY ("ownerId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "RecoveryRequest" ADD CONSTRAINT "RecoveryRequest_foundReportId_fkey" FOREIGN KEY ("foundReportId") REFERENCES "FoundReport"("id") ON DELETE SET NULL ON UPDATE CASCADE; ALTER TABLE "RecoveryRequest" ADD CONSTRAINT "RecoveryRequest_conversationId_fkey" FOREIGN KEY ("conversationId") REFERENCES "Conversation"("id") ON DELETE SET NULL ON UPDATE CASCADE; ALTER TABLE "RecoveryRequest" ADD CONSTRAINT "RecoveryRequest_finderIdentityId_fkey" FOREIGN KEY ("finderIdentityId") REFERENCES "FinderIdentity"("id") ON DELETE SET NULL ON UPDATE CASCADE;
